import React, { useState, useEffect } from "react";
import axios from "axios";

const LocationManager = () => {
  const [locations, setLocations] = useState([]);
  const [newLocation, setNewLocation] = useState({ name: "" });
  const [editingLocation, setEditingLocation] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchLocations();
  }, []);

  const fetchLocations = async () => {
    try {
      const response = await axios.get("http://localhost:5001/api/locations");
      setLocations(response.data);
    } catch (error) {
      console.error("Error fetching locations:", error);
      setError("Failed to load locations");
    }
  };

  const handleInputChange = (e, isEditing = false) => {
    const { name, value } = e.target;
    if (isEditing) {
      setEditingLocation({ ...editingLocation, [name]: value });
    } else {
      setNewLocation({ ...newLocation, [name]: value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post(
        "http://localhost:5001/api/locations",
        newLocation
      );
      setNewLocation({ name: "" });
      fetchLocations();
      setError("");
    } catch (error) {
      console.error("Error creating location:", error);
      const errorMessage =
        error.response?.data?.message || "Failed to create location";
      setError(errorMessage);
    }
  };

  const handleEdit = (location) => {
    setEditingLocation(location);
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`http://localhost:5001/api/locations/${id}`);
      fetchLocations();
    } catch (error) {
      console.error("Error deleting location:", error);
      setError("Failed to delete location");
    }
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.put(
        `http://localhost:5001/api/locations/${editingLocation._id}`,
        editingLocation
      );
      setEditingLocation(null);
      fetchLocations();
      setError("");
    } catch (error) {
      console.error("Error updating location:", error);
      const errorMessage =
        error.response?.data?.message || "Failed to update location";
      setError(errorMessage);
    }
  };

  return (
    <div className="inspector-manager">
      <h2>Manage Locations</h2>
      {/* Locations List */}
      <div className="inspectors-list">
        <h3>Current Locations</h3>
        {error && <div className="error-message">{error}</div>}
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Inspector ID</th>
                <th>Department</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {locations.map((location) => (
                <tr
                  key={location._id}
                  className={!location.active ? "inactive" : ""}
                >
                  <td>{location.name}</td>
                  <td>{location.inspectorId}</td>
                  <td>{location.department}</td>
                  <td>
                    <span
                      className={`status-badge ${
                        location.active ? "status-active" : "status-inactive"
                      }`}
                    >
                      {location.active ? "Active" : "Inactive"}
                    </span>
                  </td>
                  <td>
                    <button
                      onClick={() => handleEdit(location)}
                      className="btn btn-small btn-edit"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleToggleActive(location)}
                      className={`btn btn-small ${
                        location.active ? "btn-deactivate" : "btn-activate"
                      }`}
                    >
                      {location.active ? "Deactivate" : "Activate"}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Location Name"
          value={newLocation.name}
          onChange={(e) => handleInputChange(e)}
          required
        />
        <button type="submit">Add Location</button>
      </form>
      {editingLocation && (
        <form onSubmit={handleUpdate}>
          <input
            type="text"
            placeholder="Location Name"
            value={editingLocation.name}
            onChange={(e) => handleInputChange(e, true)}
            required
          />
          <button type="submit">Update Location</button>
          <button onClick={() => setEditingLocation(null)}>Cancel</button>
        </form>
      )}
      {error && <p>{error}</p>}
      <ul>
        {locations.map((location) => (
          <li key={location._id}>
            {location.name}
            <button onClick={() => handleEdit(location)}>Edit</button>
            <button onClick={() => handleDelete(location._id)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default LocationManager;
